typedef logic [37:0] address_t;
typedef logic [3:0] size_t;
rand size_t size;
rand address_t address;
constraint con_c { address % (1 << size) == 0; }

typedef enum { TXN_1, TXN_2, TXN_3 } txn_type_t;
rand txn_type_t req_txn_type;
rand logic [37:0] address;
constraint con_c { req_txn_type inside {TXN_1, TXN_2} -> address % (1 << 4) == 0; }
